// Aggregate all data sources into a single briefing payload
const todayTasks = $('Get Today Tasks').all().map(i => {
  const p = i.json.properties || i.json;
  return {
    id: i.json.id,
    title: p.Name?.title?.[0]?.plain_text || 'Untitled',
    project: p.Project?.select?.name || 'No Project',
    priority: p.Priority?.select?.name || 'Medium',
    context: p.Context?.select?.name || '@anywhere',
    estimated_minutes: p['Estimated Minutes']?.number || 30
  };
});

const backlogTasks = $('Get High-Priority Backlog').all().map(i => {
  const p = i.json.properties || i.json;
  return {
    id: i.json.id,
    title: p.Name?.title?.[0]?.plain_text || 'Untitled',
    project: p.Project?.select?.name || 'No Project',
    priority: p.Priority?.select?.name || 'High',
    estimated_minutes: p['Estimated Minutes']?.number || 30
  };
});

const dueTasks = $('Get Tasks Due Today').all().map(i => {
  const p = i.json.properties || i.json;
  return {
    id: i.json.id,
    title: p.Name?.title?.[0]?.plain_text || 'Untitled',
    due_date: p['Due Date']?.date?.start || 'today',
    priority: p.Priority?.select?.name || 'High'
  };
});

let calendarEvents = [];
try {
  const calData = $('Get Google Calendar Events').first().json;
  calendarEvents = (calData.items || []).map(e => ({
    title: e.summary || 'No Title',
    start: e.start?.dateTime || e.start?.date || '',
    end: e.end?.dateTime || e.end?.date || '',
    location: e.location || ''
  }));
} catch(e) {
  calendarEvents = [];
}

// Calculate total estimated time
const totalMinutes = todayTasks.reduce((sum, t) => sum + t.estimated_minutes, 0);

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    day_name: new Date().toLocaleDateString('en-US', { weekday: 'long' }),
    today_tasks: todayTasks,
    today_task_count: todayTasks.length,
    total_estimated_minutes: totalMinutes,
    backlog_candidates: backlogTasks,
    due_today_or_overdue: dueTasks,
    calendar_events: calendarEvents,
    calendar_event_count: calendarEvents.length
  }
}];

