// Parse Claude's response and extract priority rankings
const claudeResponse = $input.first().json;
const content = claudeResponse.content[0].text;

// Extract the priority order JSON from Claude's response
let priorityOrder = [];
try {
  const jsonMatch = content.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[1]);
    priorityOrder = parsed.priority_order || [];
  }
} catch (e) {
  console.log('Could not parse priority JSON from Claude response');
}

// Extract briefing text (everything before the JSON block)
const briefingText = content.replace(/```json[\s\S]*?```/, '').trim();

return [{
  json: {
    briefing_text: briefingText,
    priority_order: priorityOrder,
    date: new Date().toISOString().split('T')[0],
    day_name: new Date().toLocaleDateString('en-US', { weekday: 'long' })
  }
}];

// Split priority rankings into individual items for batch update
const data = $input.first().json;
const items = data.priority_order.map(p => ({
  json: {
    page_id: p.id,
    rank: p.rank,
    suggested_priority: p.suggested_priority,
    briefing_text: data.briefing_text,
    date: data.date
  }
}));

// If no priority items, pass through with just the briefing
if (items.length === 0) {
  return [{ json: { ...data, skip_updates: true } }];
}

return items;
